# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit
import SwiftUI

@main
struct PromoLinkApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    
    var body: some Scene {
        WindowGroup {
            ContentView()
                .onOpenURL { url in
                    UniversalLinkHandler.shared.handleUniversalLink(url)
                }
        }
    }
}

class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        UniversalLinkHandler.shared.handleUniversalLink(url)
        return true
    }
}

struct PromoCode: Codable {
    let code: String
    let discount: Int
    let appliedDate: Date
}

class UserAccount: ObservableObject {
    @Published var activePromoCodes: [PromoCode] = []
    @Published var totalDiscount: Int = 0
    
    static let shared = UserAccount()
    
    private init() {
        loadPromoCodes()
    }
    
    func applyPromoCode(code: String, discount: Int) -> Bool {
        if activePromoCodes.contains(where: { $0.code == code }) {
            return false
        }
        
        let promoCode = PromoCode(code: code, discount: discount, appliedDate: Date())
        activePromoCodes.append(promoCode)
        calculateTotalDiscount()
        savePromoCodes()
        
        NotificationCenter.default.post(name: .promoCodeApplied, object: nil, userInfo: ["code": code, "discount": discount])
        
        return true
    }
    
    func removePromoCode(code: String) {
        activePromoCodes.removeAll { $0.code == code }
        calculateTotalDiscount()
        savePromoCodes()
    }
    
    private func calculateTotalDiscount() {
        totalDiscount = activePromoCodes.reduce(0) { $0 + $1.discount }
    }
    
    private func savePromoCodes() {
        if let encoded = try? JSONEncoder().encode(activePromoCodes) {
            UserDefaults.standard.set(encoded, forKey: "activePromoCodes")
        }
    }
    
    private func loadPromoCodes() {
        if let data = UserDefaults.standard.data(forKey: "activePromoCodes"),
           let decoded = try? JSONDecoder().decode([PromoCode].self, from: data) {
            activePromoCodes = decoded
            calculateTotalDiscount()
        }
    }
}

class UniversalLinkHandler: ObservableObject {
    static let shared = UniversalLinkHandler()
    
    @Published var lastPromoCode: String?
    @Published var lastDiscount: Int?
    @Published var showPromoAlert: Bool = false
    @Published var promoMessage: String = ""
    @Published var promoSuccess: Bool = false
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) {
        guard url.host == "myapp.com" || url.host == "www.myapp.com" else {
            return
        }
        
        guard url.path == "/promo" else {
            return
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            showError(message: "Invalid promo link format")
            return
        }
        
        var promoCode: String?
        var discount: Int?
        
        for item in queryItems {
            switch item.name {
            case "code":
                promoCode = item.value
            case "discount":
                if let value = item.value, let discountValue = Int(value) {
                    discount = discountValue
                }
            default:
                break
            }
        }
        
        guard let code = promoCode, !code.isEmpty else {
            showError(message: "Promo code is missing")
            return
        }
        
        guard let discountValue = discount, discountValue > 0, discountValue <= 100 else {
            showError(message: "Invalid discount value")
            return
        }
        
        applyPromoCode(code: code, discount: discountValue)
    }
    
    private func applyPromoCode(code: String, discount: Int) {
        let success = UserAccount.shared.applyPromoCode(code: code, discount: discount)
        
        DispatchQueue.main.async {
            self.lastPromoCode = code
            self.lastDiscount = discount
            self.promoSuccess = success
            
            if success {
                self.promoMessage = "Promo code '\(code)' applied successfully! You got \(discount)% discount."
            } else {
                self.promoMessage = "Promo code '\(code)' has already been applied."
            }
            
            self.showPromoAlert = true
        }
    }
    
    private func showError(message: String) {
        DispatchQueue.main.async {
            self.promoMessage = message
            self.promoSuccess = false
            self.showPromoAlert = true
        }
    }
}

